function getValidJsonObject(rawText) {

    if (typeof rawText !== 'string' || rawText.trim() === '') {
        console.error("Invalid input or empty text field.");
        return null;
    }

    let jsonString = rawText.trim();

    // 2. Check for and remove the markdown JSON block fences.
    const markdownRegex = /^```json\s*([\s\S]*?)\s*```$/;
    const match = jsonString.match(markdownRegex);

    if (match) {
        jsonString = match[1];
    }

    // 3. Parse the cleaned string into a JSON object.
    try {
        return JSON.parse(jsonString);
    } catch (error) {
        // This is expected for parts that aren't JSON, like "```"
        // console.error("Failed to parse JSON string:", error); 
        // console.error("Problematic string:", jsonString);
        return null; // Returning null is key
    }
}

// === NEW LOGIC ===

// 1. Get the array of all parts
const allParts = $input.first().json.content.parts;

// 2. Map each part to a parse attempt.
//    - If part.text is valid JSON, we get the object.
//    - If part.text is "```" or other non-JSON, getValidJsonObject returns null.
const parsedData = allParts
    .map(part => getValidJsonObject(part.text))
    .filter(result => result !== null); // 3. Filter out all the nulls

// `parsedData` is now an array of all successfully parsed JSON objects.
// In your example, it will be: [ [ { id: "h3f8e9a1", ... } ] ]

return { data: parsedData };

